// Importing necessary libraries
import React, { Component } from 'react';
import { Platform, View, Button } from 'react-native';
import InAppBilling from 'react-native-billing';
import InAppUtils from 'react-native-in-app-utils';

class PaymentModule extends Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
    };
  }

  componentDidMount() {
    if (Platform.OS === 'ios') {
      const products = [
        'com.example.product1',
        'com.example.product2',
      ];
      InAppUtils.loadProducts(products, (error, products) => {
        if (error) {
          console.log(error);
        }

        this.setState({products});
      });
    } else if (Platform.OS === 'android') {
      InAppBilling.open()
        .then(() => InAppBilling.loadProducts(['product1', 'product2']))
        .then((products) => {
          this.setState({products});
          return InAppBilling.close();
        })
        .catch((err) => {
          console.log(err);
        });
    }
  }

  handlePayment = (productId) => {
    if (Platform.OS === 'ios') {
      InAppUtils.purchaseProduct(productId, (error, response) => {
        // handle response
      });
    } else if (Platform.OS === 'android') {
      InAppBilling.open()
        .then(() => InAppBilling.purchase(productId))
        .then((details) => {
          // handle details
          return InAppBilling.close();
        })
        .catch((err) => {
          console.log(err);
        });
    }
  }

  render() {
    return (
      <View>
        {this.state.products.map(product => (
          <Button 
            key={product.identifier} 
            title={`Buy ${product.title}`} 
            onPress={() => this.handlePayment(product.identifier)} 
          />
        ))}
      </View>
    );
  }
}

export default PaymentModule;